import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const d=JSON.parse('{"title":"职业体系生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/职业体系生成.md","filePath":"mumuainovel/职业体系生成.md","lastUpdated":1777767753000}'),e={name:"mumuainovel/职业体系生成.md"};function t(i,s,c,o,u,q){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="职业体系生成" tabindex="-1">职业体系生成 <a class="header-anchor" href="#职业体系生成" aria-label="Permalink to &quot;职业体系生成&quot;">​</a></h1><blockquote><p>模板键: <code>CAREER_SYSTEM_GENERATION</code> 分类: 世界构建 描述: 根据世界观和项目简介自动生成完整的职业体系，包括主职业和副职业 参数: [&quot;title&quot;, &quot;genre&quot;, &quot;theme&quot;, &quot;description&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的职业体系设计师，擅长为不同世界观设计完整、贴合故事的职业体系。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【设计任务】</span></span>
<span class="line"><span>根据世界观信息和项目简介，设计一个完整且合理的职业体系。</span></span>
<span class="line"><span>职业体系必须与项目简介中的故事背景和角色设定高度契合。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数量要求】</span></span>
<span class="line"><span>- 主职业：精确生成1个</span></span>
<span class="line"><span>- 副职业：精确生成1个</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;worldview priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span>简介：{description}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【世界观设定】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span>&lt;/worldview&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;guidelines priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【各类型职业设计原则】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**现代都市/言情/青春**：</span></span>
<span class="line"><span>- 职业方向：真实行业（互联网、金融、医疗、教育、法律、传媒等）</span></span>
<span class="line"><span>- 阶段体系：用职级/资历/成就代替等级（实习生→助理→主管→总监→合伙人）</span></span>
<span class="line"><span>- 阶段数建议：主职业3-6个，副职业2-4个</span></span>
<span class="line"><span>- 特殊能力：用专业技能、人脉资源、行业影响力代替超自然能力</span></span>
<span class="line"><span>- 避免：把普通职业写出修炼感</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**历史/古代**：</span></span>
<span class="line"><span>- 职业方向：传统行业（官员、商人、工匠、大夫、谋士、武将等）</span></span>
<span class="line"><span>- 阶段体系：用身份地位/声望/师承体现</span></span>
<span class="line"><span>- 阶段名称要符合时代特征</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**玄幻/仙侠/修真**：</span></span>
<span class="line"><span>- 职业方向：修炼路线、辅助技能</span></span>
<span class="line"><span>- 阶段体系：修炼境界，名称要有世界观特色</span></span>
<span class="line"><span>- 阶段数建议：主职业8-12个，副职业5-8个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**科幻**：</span></span>
<span class="line"><span>- 职业方向：未来科技、太空探索、AI等</span></span>
<span class="line"><span>- 阶段体系：用技术等级/权限/成就体现</span></span>
<span class="line"><span>- 阶段数建议：主职业5-8个，副职业3-6个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**奇幻/魔法**：</span></span>
<span class="line"><span>- 职业方向：魔法专精、冒险技能</span></span>
<span class="line"><span>- 阶段体系：魔法等级/公会认证</span></span>
<span class="line"><span>- 阶段数建议：主职业5-8个，副职业3-6个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【避免套路】</span></span>
<span class="line"><span>❌ 玄幻类不要默认生成：战士/法师/刺客三件套</span></span>
<span class="line"><span>❌ 仙侠类不要默认生成：炼丹/炼器/阵法三件套</span></span>
<span class="line"><span>❌ 现代类不要生成过于宽泛的&quot;商人&quot;&quot;企业家&quot;</span></span>
<span class="line"><span>❌ 阶段名称不要用&quot;初级/中级/高级&quot;等通用词</span></span>
<span class="line"><span>✅ 应根据简介和世界观创造独特、贴合故事的职业</span></span>
<span class="line"><span>&lt;/guidelines&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;design_requirements priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【设计要求】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**1. 主职业（main_careers）- 必须精确生成1个**</span></span>
<span class="line"><span>- 主职业是角色的核心发展方向</span></span>
<span class="line"><span>- 必须严格符合世界观规则和简介中的故事背景</span></span>
<span class="line"><span>- 每个主职业的阶段数量可以不同（体现职业复杂度差异）</span></span>
<span class="line"><span>- 职业设计要能支撑简介中描述的故事情节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**2. 副职业（sub_careers）- 必须精确生成1个**</span></span>
<span class="line"><span>- 副职业包含生产、辅助、特殊技能类</span></span>
<span class="line"><span>- 每个副职业的阶段数量可以不同</span></span>
<span class="line"><span>- 不要让所有副职业都是相同的阶段数</span></span>
<span class="line"><span>- 副职业要能为主职业提供辅助或增益</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**3. 阶段设计（stages）**</span></span>
<span class="line"><span>- 每个职业的stages数组长度必须等于max_stage</span></span>
<span class="line"><span>- 阶段名称要符合世界观文化背景（避免&quot;初级/中级/高级&quot;）</span></span>
<span class="line"><span>- 阶段描述要体现明确的能力提升路径</span></span>
<span class="line"><span>- 确保职业间的阶段数量有差异</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**4. 简介契合度**</span></span>
<span class="line"><span>- 职业体系必须与项目简介中的故事设定相匹配</span></span>
<span class="line"><span>- 如果简介中提到特定职业或能力，优先设计相关职业</span></span>
<span class="line"><span>- 职业的能力和特点要能支撑简介中的情节发展</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**5. 剧情服务**</span></span>
<span class="line"><span>- 职业体系要为主角成长提供清晰路径</span></span>
<span class="line"><span>- 职业阶段突破应能作为剧情关键节点</span></span>
<span class="line"><span>- 不同职业之间应存在合作/冲突关系（如资源争夺、理念对立）</span></span>
<span class="line"><span>- 职业特殊能力要能制造剧情张力</span></span>
<span class="line"><span>&lt;/design_requirements&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON对象：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>&quot;main_careers&quot;: [</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;职业名称&quot;,</span></span>
<span class="line"><span>  &quot;description&quot;: &quot;职业描述（100-150字）&quot;,</span></span>
<span class="line"><span>  &quot;category&quot;: &quot;职业分类&quot;,</span></span>
<span class="line"><span>  &quot;stages&quot;: [</span></span>
<span class="line"><span>    {{&quot;level&quot;: 1, &quot;name&quot;: &quot;阶段1名称&quot;, &quot;description&quot;: &quot;阶段描述&quot;}},</span></span>
<span class="line"><span>    {{&quot;level&quot;: 2, &quot;name&quot;: &quot;阶段2名称&quot;, &quot;description&quot;: &quot;阶段描述&quot;}}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;max_stage&quot;: 整数,</span></span>
<span class="line"><span>  &quot;requirements&quot;: &quot;职业要求和前置条件&quot;,</span></span>
<span class="line"><span>  &quot;special_abilities&quot;: &quot;职业特殊能力&quot;,</span></span>
<span class="line"><span>  &quot;narrative_function&quot;: &quot;该职业在故事中的作用（如：为主角提供成长路径、制造权力冲突等）&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>],</span></span>
<span class="line"><span>&quot;sub_careers&quot;: [</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;副职业名称&quot;,</span></span>
<span class="line"><span>  &quot;description&quot;: &quot;职业描述（80-120字）&quot;,</span></span>
<span class="line"><span>  &quot;category&quot;: &quot;生产系/辅助系/特殊系&quot;,</span></span>
<span class="line"><span>  &quot;stages&quot;: [</span></span>
<span class="line"><span>    {{&quot;level&quot;: 1, &quot;name&quot;: &quot;阶段1名称&quot;, &quot;description&quot;: &quot;阶段描述&quot;}}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;max_stage&quot;: 整数,</span></span>
<span class="line"><span>  &quot;requirements&quot;: &quot;职业要求&quot;,</span></span>
<span class="line"><span>  &quot;special_abilities&quot;: &quot;特殊能力&quot;,</span></span>
<span class="line"><span>  &quot;narrative_function&quot;: &quot;该副职业在故事中的辅助作用&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式规范】</span></span>
<span class="line"><span>- 纯JSON输出，无markdown标记、代码块符号</span></span>
<span class="line"><span>- 不使用特殊符号包裹内容</span></span>
<span class="line"><span>- 提供充实原创内容</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 主职业数量：必须精确生成1个，不多不少</span></span>
<span class="line"><span>✅ 副职业数量：必须精确生成1个，不多不少</span></span>
<span class="line"><span>✅ stages数组长度必须等于max_stage</span></span>
<span class="line"><span>✅ 确保职业体系与世界观高度契合</span></span>
<span class="line"><span>✅ 职业设计必须支撑项目简介中的故事情节</span></span>
<span class="line"><span>✅ 职业要为角色成长和剧情发展服务</span></span>
<span class="line"><span>✅ 阶段名称必须符合世界观文化背景，有代入感</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【阶段数量 - 按类型调整】</span></span>
<span class="line"><span>✅ 现代都市：主职业3-6个，副职业2-4个</span></span>
<span class="line"><span>✅ 玄幻仙侠：主职业8-12个，副职业5-8个</span></span>
<span class="line"><span>✅ 科幻/奇幻：主职业5-8个，副职业3-6个</span></span>
<span class="line"><span>✅ 历史古代：主职业4-8个，副职业3-5个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 所有职业使用相同的阶段数</span></span>
<span class="line"><span>❌ 输出markdown标记</span></span>
<span class="line"><span>❌ 职业设计与世界观或简介脱节</span></span>
<span class="line"><span>❌ 忽略简介中提到的职业或能力设定</span></span>
<span class="line"><span>❌ 使用&quot;初级/中级/高级&quot;等通用阶段名称</span></span>
<span class="line"><span>❌ 照搬游戏化的属性数值（如strength: +10%）</span></span>
<span class="line"><span>❌ 生成套路化、模板化的职业组合</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const _=n(e,[["render",t]]);export{d as __pageData,_ as default};
